import{_ as r,o as t,c as i,a6 as n}from"./chunks/framework.tMKqR5tb.js";const u=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/introduction.md","filePath":"getting-started/introduction.md","lastUpdated":1781548389000}'),o={name:"getting-started/introduction.md"};function a(s,e,l,d,c,p){return t(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to “Introduction”">​</a></h1><p>Papyrus Client is a <strong>Fabric-only</strong> Minecraft launcher for macOS and Windows. It is the companion client for <a href="https://docs.sushii.dev/papyrus/" target="_blank" rel="noreferrer">Papyrus server software</a>.</p><h2 id="why-papyrus-client" tabindex="-1">Why Papyrus Client? <a class="header-anchor" href="#why-papyrus-client" aria-label="Permalink to “Why Papyrus Client?”">​</a></h2><p>Vanilla Fabric mods can choose whether to identify themselves to servers. Papyrus Client ships a bundled <strong><code>papyrus-shield</code></strong> mod that:</p><ol><li>Collects <strong>every</strong> mod loaded by Fabric Loader (including mods that do not self-report)</li><li>Sends a signed integrity report to Papyrus servers over the <code>papyrus:integrity</code> channel</li><li>Runs invisibly in the launcher UI — you manage your own mods, integrity is always present</li></ol><p>Servers with <code>anticheat.client-integrity.enabled: true</code> reject players who do not send a valid report and show the <a href="/papyrus-client/download">download page</a>.</p><h2 id="fabric-only" tabindex="-1">Fabric only <a class="header-anchor" href="#fabric-only" aria-label="Permalink to “Fabric only”">​</a></h2><p>Papyrus Client does <strong>not</strong> support Forge, NeoForge, or Quilt-only profiles. Every supported Minecraft version uses Fabric Loader.</p><h2 id="supported-versions" tabindex="-1">Supported versions <a class="header-anchor" href="#supported-versions" aria-label="Permalink to “Supported versions”">​</a></h2><p>Pre-built <strong>papyrus-shield</strong> jars are published for:</p><ul><li><strong>26.1.2</strong> (matches Papyrus server; unobfuscated)</li><li><strong>1.21.11</strong>, <strong>1.21.10</strong>, <strong>1.21.8</strong></li><li>1.21.4, 1.21.1</li></ul><p>The launcher profile picker lists these first, then other Mojang release versions.</p><h2 id="microsoft-sign-in-required" tabindex="-1">Microsoft sign-in required <a class="header-anchor" href="#microsoft-sign-in-required" aria-label="Permalink to “Microsoft sign-in required”">​</a></h2><p>You must sign in with Microsoft before launching. This matches official Minecraft authentication and prevents cracked clients from joining integrity-enabled servers.</p>',14)])])}const g=r(o,[["render",a]]);export{u as __pageData,g as default};
